    public void onCreate(SQLiteDatabase db) {
        db.execSQL("CREATE TABLE user_profiles (" +
            "user_id TEXT PRIMARY KEY," +
            "encrypted_name TEXT," +
            "encrypted_email TEXT," +
            "encrypted_phone TEXT," +
            "encrypted_address TEXT)");
        
        db.execSQL("CREATE TABLE payment_info (" +
            "user_id TEXT PRIMARY KEY," +
            "encrypted_card_number TEXT," +
            "encrypted_cvv TEXT," +
            "encrypted_expiry TEXT," +
            "encrypted_cardholder TEXT," +
            "encrypted_billing_address TEXT)");
        
        db.execSQL("CREATE TABLE session_data (" +
            "session_id TEXT PRIMARY KEY," +
            "user_id TEXT," +
            "encrypted_token TEXT," +
            "encrypted_refresh_token TEXT," +
            "timestamp INTEGER)");
    }
    
    @Override
    public void onUpgrade(SQLiteDatabase db, int oldVersion, int newVersion) {
        db.execSQL("DROP TABLE IF EXISTS user_profiles");
        db.execSQL("DROP TABLE IF EXISTS payment_info");
        db.execSQL("DROP TABLE IF EXISTS session_data");
        onCreate(db);
    }
